class CyberAdmin extends React.Component {
  constructor(props) {
    super(props);
    this.editName = evt => {
      this.setState({
        openEidtName: true
      });
    };
    this.closeEdit = () => {
      this.setState({
        openEidtName: false
      });
    };
    this.upStep = evt => {
      this.setState({
        screen: 0
      });
      var setIndex = Number(evt.currentTarget.value);
      if (setIndex == 1) {
        alert("already at first");
      } else {
        var temp = this.state.distributionResult;
        //var stop = false
        for (var i in temp) {
          //if (!stop) {
          if (temp[i].index == setIndex - 1) {
            temp[i].index = setIndex;
          } else {
            if (temp[i].index == setIndex) {
              temp[i].index = setIndex - 1;
              //stop = true
            }
          }
          //}
        }

        this.setState({
          distributionResult: temp
        });
      }
      this.setState({
        screen: 1
      });
    };
    this.downStep = evt => {
      this.setState({
        screen: 0
      });
      var setIndex = Number(evt.currentTarget.value);
      if (setIndex == this.state.distributionResult.length) {
        alert("already at last");
      } else {
        var temp = this.state.distributionResult;
        var stop = false;
        for (var i in temp) {
          if (temp[i].index == setIndex + 1) {
            temp[i].index = setIndex;
          } else {
            if (temp[i].index == setIndex) {
              temp[i].index = setIndex + 1;
            }
          }
        }
        this.setState({
          distributionResult: temp
        });
      }
      this.setState({
        screen: 1
      });
    };
    this.onChangeNumberOnlyStartingCensus = e => {
      const re = /^[0-9\b]+$/;
      if (e.target.value === '' || re.test(e.target.value)) {
        this.setState({
          startingCensus: e.target.value
        });
      }
    };
    this.onChangeNumberOnlyUpCensus = e => {
      const re = /^[0-9\b]+$/;
      if (e.target.value === '' || re.test(e.target.value)) {
        this.setState({
          upCensus: e.target.value
        });
      }
    };
    this.onChangeAssignHO = selectedOptions => {
      this.setState({
        ho: selectedOptions
      });
    };
    this.onChangeTeam = selectedOptions => {
      this.setState({
        team: selectedOptions
      });
    };
    this.onChangeStartingCensus = selectedOptions => {
      this.setState({
        startCensusFewer: selectedOptions
      });
    };
    this.onChangeMaxHo = selectedOptions => {
      this.setState({
        maxho: selectedOptions
      });
    };
    this.onChangeResintern = selectedOptions => {
      this.setState({
        resintern: selectedOptions
      });
    };
    this.onChangeFullTeam = selectedOptions => {
      this.setState({
        fullteam: selectedOptions
      });
    };
    this.deleteStep = evt => {
      var distributionResult = this.state.distributionResult;
      var setIndex = Number(evt.currentTarget.value);
      var startDelete = false;
      var tempResult = [];
      for (var i in distributionResult) {
        if (distributionResult[i].index == setIndex) {
          startDelete = true;
        } else {
          if (startDelete) {
            distributionResult[i].index -= 1;
          }
          tempResult.push(distributionResult[i]);
        }
      }
      this.setState({
        distributionResult: tempResult
      });
    };
    this.createNewAlgorithm = evt => {
      this.setState({
        screen: 2
      });
    };
    this.cancelCreate = () => {
      this.setState({
        ho: {}
      });
      this.setState({
        team: {}
      });
      this.setState({
        startCensusFewer: {}
      });
      this.setState({
        maxho: {}
      });
      this.setState({
        resintern: {}
      });
      this.setState({
        fullteam: {}
      });
      this.setState({
        startingCensus: ""
      });
      this.setState({
        upCensus: ""
      });
      this.setState({
        screen: 1
      });
    };
    this.handleCreateAlgorithm = () => {
      var errorMsg = "";
      if (JSON.stringify(this.state.ho) == "{}") {
        errorMsg += "please select how many/position HO assign\n";
      }
      if (JSON.stringify(this.state.team) == "{}") {
        errorMsg += "please select which team\n";
      }
      if (JSON.stringify(this.state.startCensusFewer) != "{}" && this.state.startCensusFewer.value != "" && this.state.startingCensus == "") {
        console.log(this.state.startCensusFewer.value);
        errorMsg += "please enter starting census #\n";
      }
      if (errorMsg == "") {
        var requestData = {};
        if (this.state.ho.value === "1stHO") {
          requestData.ho = 1;
          requestData.current_ho = 0;
        }
        if (this.state.ho.value === "2ndHO") {
          requestData.ho = 1;
          requestData.current_ho = 1;
        }
        if (this.state.ho.value === "3rdHO") {
          requestData.ho = 1;
          requestData.current_ho = 2;
        }
        if (this.state.ho.value === "4thHO") {
          requestData.ho = 1;
          requestData.current_ho = 3;
        }
        if (this.state.ho.value === "upto1") {
          requestData.ho = 1;
        }
        if (this.state.ho.value === "upto2") {
          requestData.ho = 2;
        }
        if (this.state.ho.value === "upto3") {
          requestData.ho = 3;
        }
        if (this.state.ho.value === "upto4") {
          requestData.ho = 4;
        }
        requestData.type = this.state.team.value;
        if (JSON.stringify(this.state.startCensusFewer) != "{}" && this.state.startCensusFewer.value != "" && this.state.startingCensus != "") {
          requestData.census = this.state.startingCensus;
          if (this.state.startCensusFewer.value == "fewer") {
            requestData.census = this.state.startingCensus * -1;
          }
        } else {
          if (this.state.startingCensus != "") {
            requestData.census = this.state.startingCensus;
          }
        }
        if (this.state.upCensus != "") {
          requestData.max_census = this.state.upCensus;
        }
        if (JSON.stringify(this.state.maxho) != "{}") {
          requestData.max_ho = this.state.maxho.value;
        }
        if (JSON.stringify(this.state.resintern) != "{}") {
          requestData.resintern = false;
          if (this.state.resintern.value == "yes") requestData.resintern = true;
        }
        if (JSON.stringify(this.state.fullteam) != "{}") {
          requestData.fullteam = false;
          if (this.state.fullteam.value == "yes") requestData.fullteam = true;
        }
        console.log(requestData);
        this.submitCreateAlgorithm(requestData);
      } else {
        alert(errorMsg);
      }

      //this.submitPage(pageRequest, oldValue)
    };
    this.submitCreateAlgorithm = requestData => {
      this.setState({
        screen: 0
      });
      let headers = new Headers();
      headers.append('Content-Type', 'application/json');
      headers.append('Accept', 'application/json');
      var backUrl = properties.backend + `cyberraptor/createalgorithm`;
      fetch(backUrl, {
        "method": "POST",
        headers: headers,
        body: JSON.stringify(requestData)
      }).then(response => response.json()).then(response => {
        if (response.message != "success") {
          this.setState({
